import{_ as a,o as n,c as t,a2 as r}from"./chunks/framework.BWuWLRhz.js";const v=JSON.parse('{"title":"Environment Variables","description":"","frontmatter":{},"headers":[],"relativePath":"app/variables.md","filePath":"app/variables.md"}'),i={name:"app/variables.md"};function s(o,e,l,c,d,p){return n(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h1><p>Environment variables are key/value pairs injected into your containers at <strong>build and runtime</strong>. Use them for configuration and secrets such as <code>DATABASE_URL</code> or API tokens. Variables are scoped: a variable can apply to the whole project or to a single <a href="/app/environments">environment</a>, and environment values override project values.</p><h2 id="inheritance-and-scope" tabindex="-1">Inheritance and scope <a class="header-anchor" href="#inheritance-and-scope" aria-label="Permalink to &quot;Inheritance and scope&quot;">​</a></h2><p>Each variable belongs to a project and a branch and carries two flags:</p><ul><li><strong>Secret</strong> — the value is stored encrypted and shown masked in the UI and in logs.</li><li><strong>Inherited</strong> — the value is automatically passed down to child environments, so a value set once on a parent branch is available to its previews.</li></ul><p>The variables table marks each row accordingly: <strong>Inherited</strong> (passed down from a parent scope) or <strong>This environment only</strong> (defined on the current branch). When the same key exists at multiple levels, the <strong>environment</strong> value wins over the project value.</p><div class="tip custom-block"><p class="custom-block-title">Editing scope</p><p>You can only edit or delete variables that are defined on the <strong>current</strong> environment. Inherited values are managed where they were originally defined.</p></div><h2 id="create-a-variable" tabindex="-1">Create a variable <a class="header-anchor" href="#create-a-variable" aria-label="Permalink to &quot;Create a variable&quot;">​</a></h2><ol><li>Open <strong>Environment variables</strong> for the active environment and click <strong>New variable</strong>.</li><li>Enter a <strong>Key</strong> — uppercase letters, digits and underscores (e.g. <code>DATABASE_URL</code>).</li><li>Enter the <strong>Value</strong>.</li><li>Optionally tick <strong>Secret</strong> (store encrypted, mask in UI/logs) and/or <strong>Inherited</strong> (pass down to child environments).</li><li>Click <strong>Create variable</strong>.</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Key:   STRIPE_SECRET_KEY</span></span>
<span class="line"><span>Value: sk_live_...</span></span>
<span class="line"><span>[x] Secret</span></span>
<span class="line"><span>[ ] Inherited</span></span></code></pre></div><h2 id="edit-or-delete-a-variable" tabindex="-1">Edit or delete a variable <a class="header-anchor" href="#edit-or-delete-a-variable" aria-label="Permalink to &quot;Edit or delete a variable&quot;">​</a></h2><p>In the table, click a key to edit it, or use the trash icon to delete it and confirm in the dialog.</p><div class="warning custom-block"><p class="custom-block-title">Takes effect on next deploy</p><p>Adding, changing or deleting a variable does not touch running containers. <a href="/app/environments">Redeploy</a> the environment for the change to be applied.</p></div><h2 id="not-the-same-as-relationship-variables" tabindex="-1">Not the same as relationship variables <a class="header-anchor" href="#not-the-same-as-relationship-variables" aria-label="Permalink to &quot;Not the same as relationship variables&quot;">​</a></h2><p>These user-defined variables are distinct from the <code>TRAGWERK_*</code> variables that Tragwerk injects from your <code>&lt;relationships&gt;</code> configuration. Relationship variables describe connections to backing <a href="/app/services">services</a> (database, cache, etc.) and are generated automatically — you do not create them here. See <a href="/config/relationships">relationships</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/config/relationships">Relationships configuration</a></li><li><a href="/app/services">Services</a></li><li><a href="/app/environments">Environments</a></li><li><a href="/app/deployments">Deployments</a></li></ul>`,17)])])}const b=a(i,[["render",s]]);export{v as __pageData,b as default};
